<section class="admin-shell"><?php require __DIR__.'/_nav.php';?><div class="admin-main"><div class="admin-head"><div><span class="eyebrow">ANALYTICS</span><h1>Reports and Statistics</h1></div><button class="btn outline" onclick="window.print()">Print Report</button></div><div class="report-grid"><article class="admin-panel"><h2>Monthly Appointments</h2><table><thead><tr><th>Month</th><th>Total</th><th>Completed</th><th>Cancelled</th></tr></thead><tbody><?php foreach($report['monthly']as$r):?><tr><td><?=e($r['month'])?></td><td><?=$r['total']?></td><td><?=$r['completed']?></td><td><?=$r['cancelled']?></td></tr><?php endforeach;?></tbody></table></article><article class="admin-panel"><h2>Department Demand</h2><?php $max=max(1,...array_column($report['departments'],'total'));foreach($report['departments']as$r):?><div class="report-bar"><div><span><?=e($r['name'])?></span><b><?=$r['total']?></b></div><i style="width:<?=round($r['total']/$max*100)?>%"></i></div><?php endforeach;?></article><article class="admin-panel"><h2>Doctor Workload</h2><?php $max=max(1,...array_column($report['doctors'],'total'));foreach($report['doctors']as$r):?><div class="report-bar"><div><span><?=e($r['name'])?></span><b><?=$r['total']?></b></div><i style="width:<?=round($r['total']/$max*100)?>%"></i></div><?php endforeach;?></article></div></div></section>

